/*
 * Studio Kit — Design Tokens
 * Dark é o tema principal. Light é override via .light ou [data-theme="light"].
 * Ajuste as variáveis RGB para adaptar a marca do cliente.
 */

@import url('https://fonts.googleapis.com/css2?family=Manrope:wght@400;500;600;700;800&display=swap');

/* ─── Dark (padrão) ─────────────────────────────────────────── */
:root {
  --background:           8 20 36;
  --background-secondary: 3 12 23;
  --card:                 8 20 36;

  --foreground:           232 244 251;
  --foreground-muted:     232 244 251;
  --foreground-subtle:    232 244 251;

  --accent:               0 173 207;
  --accent-foreground:    232 244 251;

  --primary:              0 173 207;
  --primary-foreground:   232 244 251;
  --secondary:            3 12 23;
  --secondary-foreground: 232 244 251;
  --muted:                8 20 36;
  --muted-foreground:     232 244 251;
  --border:               0 173 207;
  --input:                0 173 207;
  --ring:                 0 173 207;
  --destructive:          239 68 68;
  --destructive-foreground: 232 244 251;

  --radius: 0.5rem;

  --border-alpha:         0.18;
  --border-card-alpha:    0.25;
  --border-subtle-alpha:  0.10;

  --font-sans: 'Manrope', system-ui, sans-serif;
}

/* ─── Light (override) ───────────────────────────────────────── */
.light,
[data-theme="light"] {
  --background:           248 250 252;
  --background-secondary: 241 245 249;
  --card:                 255 255 255;

  --foreground:           8 20 36;
  --foreground-muted:     8 20 36;
  --foreground-subtle:    8 20 36;

  --primary:              0 173 207;
  --primary-foreground:   255 255 255;
  --secondary:            241 245 249;
  --secondary-foreground: 8 20 36;
  --muted:                241 245 249;
  --muted-foreground:     8 20 36;
  --border:               0 173 207;
  --input:                0 173 207;
  --ring:                 0 173 207;
}

/* ─── Base ───────────────────────────────────────────────────── */
*,
*::before,
*::after {
  border-color: rgb(var(--border) / var(--border-alpha, 0.18));
}

body {
  background-color: rgb(var(--background));
  color: rgb(var(--foreground) / 0.92);
  font-family: var(--font-sans);
  -webkit-font-smoothing: antialiased;
}
